i/routes.py","backend/main.py","frontend/package.json","frontend/src/components/Sidebar.js","frontend/src/components/Dashboard.js","frontend/src/components/AuditReport.js","frontend/src/App.js"],"Full API spec":"openapi: 3.0.0\\ninfo:\\n  title: System Audit & Optimization API\\n  version: 1.0.0\\npaths:\\n  /api/v1/dashboard/stats:\\n    get:\\n      summary: جلب إحصائيات النظام العامة وأداء قاعدة البيانات\\n      responses:\\n        \'200\':\\n          description: نجاح العملية وإرجاع البيانات\\n  /api/v1/audit/trigger:\\n    post:\\n      summary: تشغيل فحص أمني جديد للكود والمكتبات\\n      responses:\\n        \'200\':\\n          description: تم بدء الفحص وإرجاع التقرير بنجاح\\n  /api/v1/db/performance:\\n    get:\\n      summary: جلب تفاصيل أداء قاعدة البيانات والاستعلامات البطيئة\\n      responses:\\n        \'200\':\\n          description: نجاح جلب تقرير الأداء","Shared Knowledge":"1. يتم استخدام مكتبة `loguru` لتسجيل جميع الأحداث والأخطاء في الخلفية بشكل موحد.\\n2. يتم تخزين إعدادات الاتصال بقاعدة البيانات والمفاتيح السرية في ملف `.env` ويتم قراءتها عبر `backend/config.py`.\\n3. تعتمد الواجهة الأمامية على نظام ألوان موحد (أزرق داكن ورمادي فاتح) يتم تعريفه في إعدادات Tailwind CSS.","Anything UNCLEAR":"1. ما هو نوع قاعدة البيانات المستهدفة حالياً (PostgreSQL أم MySQL أم غيرها) لضبط محرك SQLAlchemy بشكل دقيق؟\\n2. هل الفحص الأمني عبر `bandit` سيتم تشغيله على مجلد المشروع الحالي نفسه أم سيتم تحديد مسار خارجي لفحصه؟\\n3. هل هناك حاجة لدعم تصدير التقارير بصيغة PDF مباشرة من الواجهة الخلفية أم نكتفي بتنسيقها في الواجهة الأمامية للطباعة؟"}'}}}
